step.text:
DECLARE PARAMETER country TYPE TEXT;
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);
EXTRACT weather FROM weather_csv USING CSV;

DECLARE PARAMETER country TYPE TEXT;
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);
EXTRACT weather FROM weather_csv USING CSV;

DECLARE PARAMETER country TYPE TEXT;
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);
EXTRACT weather FROM weather_csv USING CSV;
SELECT * INTO weather_avg FROM weather;

DECLARE PARAMETER country TYPE TEXT;
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);
EXTRACT weather FROM weather_csv USING CSV;
SELECT * INTO weather_avg FROM weather;
VIZ weather_avg USING LINE;
VIZ weather_avg USING TABLE;

DECLARE PARAMETER country TYPE TEXT;
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);
EXTRACT weather FROM weather_csv USING CSV;
SELECT * INTO weather_avg FROM weather;
SELECT * INTO weather_binned FROM weather;
VIZ weather_avg USING LINE;
VIZ weather_binned USING BAR;

DECLARE PARAMETER country TYPE TEXT;
DECLARE PARAMETER month TYPE INTEGER;
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);
EXTRACT weather FROM weather_csv USING CSV;
SELECT * INTO weather_avg FROM weather WHERE month = global.month;
SELECT * INTO weather_binned FROM weather WHERE month = global.month;
VIZ weather_avg USING LINE;
VIZ weather_binned USING BAR;

DECLARE PARAMETER country TYPE TEXT;
DECLARE PARAMETER city TYPE TEXT;
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);
EXTRACT weather FROM weather_csv USING CSV;
SELECT * INTO weather_avg FROM weather WHERE city = global.city;

DECLARE PARAMETER country1 TYPE TEXT;
DECLARE PARAMETER country2 TYPE TEXT;
DECLARE PARAMETER month TYPE INTEGER;
LOAD country1_weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country1)
);
LOAD country2_weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country2)
);
EXTRACT country1_weather FROM country1_weather_csv USING CSV;
EXTRACT country2_weather FROM country2_weather_csv USING CSV;
SELECT * INTO countries_joined FROM country1_weather c1, country2_weather c2 WHERE c1.month = c2.month AND c2.month = global.month;
VIZ countries_joined USING LINE;

CREATE TABLE foo AS SELECT v::INTEGER FROM generate_series(0, 100) AS t(v);
VISUALIZE weather_avg USING STACKED BAR (
    position = (r = 0, c = 0, w = 4, h = 15),
    x = a,
    y = b,
    categories = c,
    theme = 'grayscale',
    colors = ['#aaa', '#bbb', '#ccc']
), LINE (
    style.data = (
        stroke = '#c43a31'
    ),
    style.labels = (
        font_size = 15,
        fill = 'red',
    )
), SCATTER (
    style = (
        data = (
            fill = '#c43a31',
            fill_opacity = 0.6,
            stroke = '#c43a31',
            stroke_width = 3,
        )
    )
), X AXIS(scale = 'time'), Y AXIS(scale = 'log');
